const sharp = require('sharp')
const fs = require('fs')
const path = require('path')

const publicDir = path.join(__dirname, '..', 'src', 'renderer', 'public')

const targetDirs = [
  { path: path.join(publicDir, 'OutputSocialAds'), filter: (f) => f.match(/^t\d+\.png$/) },
  { path: path.join(publicDir, 'VtonModels'), filter: (f) => f.endsWith('.png') },
  { path: path.join(publicDir, 'VtonVibes'), filter: (f) => f.endsWith('.png') }
]

async function compressTemplates() {
  let beforeTotal = 0
  let afterTotal = 0
  let processedCount = 0

  for (const dirConfig of targetDirs) {
    if (!fs.existsSync(dirConfig.path)) continue

    const files = fs.readdirSync(dirConfig.path)
    const templateFiles = files.filter(dirConfig.filter)

    console.log(
      `\n🚀 Found ${templateFiles.length} templates in ${path.basename(dirConfig.path)}...`
    )

    for (const file of templateFiles) {
      // Skip if it's already a thumbnail or doesn't need thumbnailing
      if (file.includes('.thumb.')) continue

      const inputPath = path.join(dirConfig.path, file)
      const outputName = file.replace('.png', '.thumb.webp')
      const outputPath = path.join(dirConfig.path, outputName)

      // Skip if thumb already exists and is newer than source? No, just overwrite to be safe.
      const stats = fs.statSync(inputPath)
      beforeTotal += stats.size

      try {
        await sharp(inputPath)
          .resize(400) // Width 400px, auto height
          .webp({ quality: 80 })
          .toFile(outputPath)

        const outStats = fs.statSync(outputPath)
        afterTotal += outStats.size
        processedCount++

        console.log(
          `✅ Compressed ${file} -> ${outputName} (${(outStats.size / 1024).toFixed(1)} KB)`
        )
      } catch (err) {
        console.error(`❌ Error processing ${file}:`, err)
      }
    }
  }

  console.log('\n--- COMPRESSION REPORT ---')
  console.log(`Total Files Processed: ${processedCount}`)
  console.log(`Before (Total PNG): ${(beforeTotal / (1024 * 1024)).toFixed(2)} MB`)
  console.log(`After (Total WebP Thumbnails): ${(afterTotal / (1024 * 1024)).toFixed(2)} MB`)

  if (beforeTotal > 0) {
    console.log(`Reduction: ${(((beforeTotal - afterTotal) / beforeTotal) * 100).toFixed(1)}%`)
  }
}

compressTemplates()

import Database from 'better-sqlite3'
import { app } from 'electron'
import path from 'path'
import fs from 'fs'

export class DatabaseService {
  private db: Database.Database

  constructor() {
    const userDataPath = app.getPath('userData')
    const dbPath = path.join(userDataPath, 'monstercreative.db')

    // Ensure directory exists
    if (!fs.existsSync(userDataPath)) {
      fs.mkdirSync(userDataPath, { recursive: true })
    }

    this.db = new Database(dbPath)
    this.init()
  }

  private init(): void {
    try {
      this.db.exec(`
        CREATE TABLE IF NOT EXISTS app_settings (
          id INTEGER PRIMARY KEY,
          default_copy_tone TEXT,
          default_image_model TEXT,
          default_video_model TEXT,
          default_image_format TEXT,
          auto_save_generations INTEGER,
          asset_save_path TEXT,
          accent_color TEXT
        );

        INSERT OR IGNORE INTO app_settings (id, default_copy_tone, default_image_model, default_video_model, default_image_format, auto_save_generations, asset_save_path, accent_color)
        VALUES (1, 'Professional', 'FLUX Pro 1.1', 'Kling 2.0', '1:1', 1, 'C:\\MonsterCreative\\Assets', 'Blue');

        CREATE TABLE IF NOT EXISTS campaigns (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          name TEXT NOT NULL,
          platforms TEXT NOT NULL,
          status TEXT NOT NULL DEFAULT 'Draft',
          created_at TEXT NOT NULL,
          updated_at TEXT NOT NULL
        );

        CREATE TABLE IF NOT EXISTS generated_images (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          campaign_id INTEGER,
          local_path TEXT,
          prompt TEXT,
          model TEXT,
          format TEXT,
          width INTEGER,
          height INTEGER,
          fal_request_id TEXT,
          created_at TEXT
        );

        CREATE TABLE IF NOT EXISTS generated_videos (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          campaign_id INTEGER,
          local_path TEXT,
          prompt TEXT,
          model TEXT,
          format TEXT,
          duration_seconds INTEGER,
          source_type TEXT,
          source_path TEXT,
          fal_request_id TEXT,
          created_at TEXT
        );

        CREATE TABLE IF NOT EXISTS copy_variants (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          campaign_id INTEGER,
          variant_type TEXT,
          platform TEXT,
          headline1 TEXT,
          headline2 TEXT,
          headline3 TEXT,
          hook TEXT,
          body_copy TEXT,
          cta TEXT,
          tone TEXT,
          triggers_used TEXT,
          landing_page_part TEXT,
          video_scripts TEXT,
          created_at TEXT
        );

        CREATE TABLE IF NOT EXISTS custom_voices (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          name TEXT NOT NULL,
          embedding_path TEXT NOT NULL,
          sample_path TEXT,
          created_at TEXT NOT NULL
        );
      `)
    } catch (err) {
      console.error('Database core init failed:', err)
    }

    // --- MIGRATIONS ---
    const migrations = [
      'ALTER TABLE generated_videos ADD COLUMN resolution TEXT;',
      'ALTER TABLE generated_videos ADD COLUMN url TEXT;',
      'ALTER TABLE generated_videos ADD COLUMN file_name TEXT;',
      'ALTER TABLE generated_videos ADD COLUMN file_size INTEGER;',
      'ALTER TABLE generated_videos ADD COLUMN created_at TEXT;'
    ]

    for (const sql of migrations) {
      try {
        this.db.exec(sql)
      } catch (err: any) {
        // Ignore "duplicate column name" errors
        if (!err.message.includes('duplicate column name')) {
          console.error('Migration failed:', sql, err)
        }
      }
    }
  }

  // --- Settings ---
  getSettings() {
    return this.db.prepare('SELECT * FROM app_settings WHERE id = 1').get()
  }

  updateSettings(settings: any) {
    const stmt = this.db.prepare(`
      UPDATE app_settings SET 
        default_copy_tone = ?, 
        default_image_model = ?, 
        default_video_model = ?, 
        default_image_format = ?, 
        auto_save_generations = ?, 
        asset_save_path = ?, 
        accent_color = ?
      WHERE id = 1
    `)
    return stmt.run(
      settings.default_copy_tone,
      settings.default_image_model,
      settings.default_video_model,
      settings.default_image_format,
      settings.auto_save_generations ? 1 : 0,
      settings.asset_save_path,
      settings.accent_color
    )
  }

  // --- Campaigns ---
  getAllCampaigns() {
    return this.db.prepare('SELECT * FROM campaigns ORDER BY created_at DESC').all()
  }

  createCampaign(name: string, platforms: string) {
    const now = new Date().toISOString()
    const stmt = this.db.prepare(`
      INSERT INTO campaigns (name, platforms, status, created_at, updated_at)
      VALUES (?, ?, 'Draft', ?, ?)
    `)
    const result = stmt.run(name, platforms, now, now)
    return result.lastInsertRowid
  }

  // --- Content Saving ---
  saveImage(img: any) {
    const stmt = this.db.prepare(`
      INSERT INTO generated_images
        (campaign_id, local_path, prompt, model, format, width, height, fal_request_id, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    `)
    return stmt.run(
      img.campaign_id,
      img.local_path,
      img.prompt,
      img.model,
      img.format,
      img.width,
      img.height,
      img.fal_request_id,
      new Date().toISOString()
    ).lastInsertRowid
  }

  saveCopyVariant(v: any) {
    const stmt = this.db.prepare(`
      INSERT INTO copy_variants
        (campaign_id, variant_type, platform, headline1, headline2, headline3,
         hook, body_copy, cta, tone, triggers_used, landing_page_part, video_scripts, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `)
    return stmt.run(
      v.campaign_id,
      v.variant_type,
      v.platform,
      v.headline1,
      v.headline2,
      v.headline3,
      v.hook,
      v.body_copy,
      v.cta,
      v.tone,
      v.triggers_used,
      v.landing_page_part,
      v.video_scripts,
      new Date().toISOString()
    ).lastInsertRowid
  }

  saveGeneratedVideo(video: any) {
    const stmt = this.db.prepare(`
      INSERT INTO generated_videos
        (prompt, model, resolution, duration_seconds, url, file_name, file_size, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `)
    return stmt.run(
      video.prompt,
      video.model,
      video.resolution,
      video.duration,
      video.url,
      video.fileName,
      video.fileSize,
      video.createdAt || new Date().toISOString()
    ).lastInsertRowid
  }

  // --- Custom Voices ---
  saveCustomVoice(voice: { name: string; embeddingPath: string; samplePath?: string }) {
    const stmt = this.db.prepare(`
      INSERT INTO custom_voices (name, embedding_path, sample_path, created_at)
      VALUES (?, ?, ?, ?)
    `)
    const result = stmt.run(
      voice.name,
      voice.embeddingPath,
      voice.samplePath || null,
      new Date().toISOString()
    )
    return result.lastInsertRowid
  }

  getAllCustomVoices() {
    return this.db.prepare('SELECT * FROM custom_voices ORDER BY created_at DESC').all()
  }

  deleteCustomVoice(id: number) {
    return this.db.prepare('DELETE FROM custom_voices WHERE id = ?').run(id)
  }
}

export const dbService = new DatabaseService()

import { app, shell, BrowserWindow, ipcMain } from 'electron'
import { join } from 'path'
import { autoUpdater } from 'electron-updater'
import log from 'electron-log'
import { electronApp, optimizer, is } from '@electron-toolkit/utils'
import icon from '../../resources/icon.png?asset'
import { dbService } from './database'
import { keystoreService } from './keystore'
import { licenseService } from './services/license.service'
import {
  BillingService,
  TextService,
  ImageService,
  VideoService,
  AudioService
} from './services/fal'
import fs from 'fs'
import path from 'path'

const billingService = new BillingService()
const textService = new TextService()
const imageService = new ImageService()
const videoService = new VideoService()
const audioService = new AudioService()

function createWindow(): void {
  // Create the browser window.
  const mainWindow = new BrowserWindow({
    title: 'MonsterCreative',
    width: 1200,
    height: 800,
    show: false,
    autoHideMenuBar: true,
    titleBarStyle: 'hidden',
    titleBarOverlay: {
      color: '#07070F',
      symbolColor: '#FFFFFF',
      height: 32
    },
    icon,
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      sandbox: false,
      webSecurity: false
    }
  })

  mainWindow.on('ready-to-show', () => {
    mainWindow.show()
  })

  mainWindow.webContents.setWindowOpenHandler((details) => {
    shell.openExternal(details.url)
    return { action: 'deny' }
  })

  // HMR for renderer base on electron-vite cli.
  // Load the remote URL for development or the local html file for production.
  if (is.dev && process.env['ELECTRON_RENDERER_URL']) {
    mainWindow.loadURL(process.env['ELECTRON_RENDERER_URL'])
  } else {
    mainWindow.loadFile(join(__dirname, '../renderer/index.html'))
  }

  if (!is.dev) {
    // IMPORTANT: For a private repo, electron-updater needs a token to read releases.
    // DANGER: We are embedding a token. You should generate a "Fine-Grained" Personal Access Token
    // that ONLY has "Read" access to "Contents" and "Metadata" of this repository.
    // Do NOT use your full-access classic token here in production for security!
    autoUpdater.setFeedURL({
      provider: 'github',
      owner: 'lbahi',
      repo: 'MonsterCreative',
      private: true,
      token:
        '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'
    })

    autoUpdater.logger = log
    // @ts-ignore
    autoUpdater.logger.transports.file.level = 'info'

    log.info('App version:', app.getVersion())
    log.info('Checking for updates...')

    autoUpdater.on('checking-for-update', () => {
      log.info('Checking for update...')
    })

    autoUpdater.on('update-available', (info) => {
      log.info('Update available:', info)
    })

    autoUpdater.on('update-not-available', (info) => {
      log.info('Update NOT available:', info)
    })

    autoUpdater.on('error', (err) => {
      log.error('Updater error:', err)
    })

    autoUpdater.on('download-progress', (p) => {
      log.info('Download progress:', p.percent)
    })

    autoUpdater.on('update-downloaded', (info) => {
      log.info('Update downloaded:', info)
    })

    autoUpdater.checkForUpdatesAndNotify()
  }

  autoUpdater.on('update-available', () => {
    mainWindow.webContents.send('update:available')
  })

  autoUpdater.on('update-downloaded', () => {
    mainWindow.webContents.send('update:downloaded')
  })

  ipcMain.handle('update:install', () => {
    autoUpdater.quitAndInstall()
  })
}

// Support for YouTube embeds and silencing dxcompiler.dll warnings
app.disableHardwareAcceleration()

// This method will be called when Electron has finished
// initialization and is ready to create browser windows.
// Some APIs can only be used after this event occurs.
app.whenReady().then(() => {
  // Set app user model id for windows
  electronApp.setAppUserModelId('com.electron')

  // Default open or close DevTools by F12 in development
  // and ignore CommandOrControl + R in production.
  // see https://github.com/alex8088/electron-toolkit/tree/master/packages/utils
  app.on('browser-window-created', (_, window) => {
    optimizer.watchWindowShortcuts(window)
  })

  // IPC Handlers: Database
  ipcMain.handle('db:getSettings', () => dbService.getSettings())
  ipcMain.handle('db:updateSettings', (_, settings) => dbService.updateSettings(settings))
  ipcMain.handle('db:getAllCampaigns', () => dbService.getAllCampaigns())
  ipcMain.handle('db:createCampaign', (_, name, platforms) =>
    dbService.createCampaign(name, platforms)
  )
  ipcMain.handle('db:saveImage', (_, img) => dbService.saveImage(img))
  ipcMain.handle('db:saveCopyVariant', (_, v) => dbService.saveCopyVariant(v))
  // ipcMain.handle('db:saveVideo', (_, vid) => dbService.saveVideo(vid))

  // IPC Handlers: Keystore
  ipcMain.handle('key:setFalKey', (_, key) => keystoreService.setFalKey(key))
  ipcMain.handle('key:getFalKey', () => keystoreService.getFalKey())
  ipcMain.handle('key:deleteFalKey', () => keystoreService.deleteFalKey())

  // IPC Handlers: License
  ipcMain.handle('license:activate', async (_, key: string) => {
    return await licenseService.activate(key)
  })

  ipcMain.handle('license:validate', async () => {
    return await licenseService.validate()
  })

  ipcMain.handle('license:deactivate', async () => {
    return await licenseService.deactivate()
  })

  ipcMain.handle('license:getKey', async () => {
    return await keystoreService.getLicenseData('license-key')
  })

  // IPC Handlers: Fal
  ipcMain.handle('fal:generateCopy', (_, promptOrMessages, modelId) =>
    textService.generateCopy(promptOrMessages, modelId)
  )
  ipcMain.handle('fal:analyzeImageVision', (_, imageUrl, prompt, systemPrompt, modelId) =>
    textService.analyzeImageVision(imageUrl, prompt, systemPrompt, modelId)
  )
  ipcMain.handle('fal:chatCompletion', (_, messages, modelId) =>
    textService.chatCompletion(messages, modelId)
  )
  ipcMain.handle('fal:getUsage', (_, timeframe, start, end) =>
    billingService.getUsage(timeframe, start, end)
  )
  ipcMain.handle('fal:getBilling', () => billingService.getBilling())
  ipcMain.handle('fal:validateKey', (_, key) => billingService.validateKey(key))
  ipcMain.handle('fal:getPricing', (_, ids) => billingService.getPricing(ids))
  ipcMain.handle('fal:getAnalytics', (_, ids, start, end) =>
    billingService.getAnalytics(ids, start, end)
  )
  ipcMain.handle('fal:uploadImageFromDataUrl', (_, dataUrl) =>
    imageService.uploadImageFromDataUrl(dataUrl)
  )
  ipcMain.handle('fal:nanoBananaEdit', (_, params) => imageService.nanoBananaEdit(params))
  ipcMain.handle('fal:reframeImage', (_, params) => imageService.reframeImage(params))
  ipcMain.handle('fal:kontextEdit', (_, params) => imageService.kontextEdit(params))
  ipcMain.handle('fal:generateVideo', (_, params) => videoService.generateVideo(params))

  ipcMain.handle('video:generate', async (_event, request: any) => {
    try {
      const result = await videoService.generateVideo(request)

      // Persist to database
      await dbService.saveGeneratedVideo({
        prompt: request.prompt,
        model: request.modelId || 'fal-ai/pixverse/v6/image-to-video',
        resolution: request.resolution,
        duration: request.duration,
        url: result.url,
        fileName: result.fileName,
        fileSize: result.fileSize,
        createdAt: new Date().toISOString()
      })

      return { success: true, data: result }
    } catch (error: any) {
      console.error('[IPC video:generate] Error:', error)
      return { success: false, error: error.message }
    }
  })

  // IPC Handlers: Utils
  ipcMain.handle('util:openExternal', async (_, url) => {
    await shell.openExternal(url)
  })

  // IPC Handlers: Social Ads — save generated image to renderer public folder
  ipcMain.handle(
    'social:saveAdImage',
    async (_, { imageUrl, filename }: { imageUrl: string; filename: string }) => {
      try {
        // In production, save next to the renderer html; in dev, save to public folder
        const rendererDir = is.dev
          ? path.join(__dirname, '../../src/renderer/public/OutputSocialAds')
          : path.join(__dirname, '../renderer/OutputSocialAds')

        if (!fs.existsSync(rendererDir)) fs.mkdirSync(rendererDir, { recursive: true })

        const safeName = filename.replace(/[^a-zA-Z0-9_\-\.]/g, '_')
        const destPath = path.join(rendererDir, safeName)

        const resp = await fetch(imageUrl)
        if (!resp.ok) throw new Error(`Failed to fetch image: ${resp.status}`)
        const buffer = Buffer.from(await resp.arrayBuffer())
        fs.writeFileSync(destPath, buffer)

        return { success: true, path: destPath, localUrl: `./OutputSocialAds/${safeName}` }
      } catch (error: any) {
        console.error('[social:saveAdImage]', error)
        return { success: false, error: error.message }
      }
    }
  )

  ipcMain.handle('social:openOutputFolder', async () => {
    const rendererDir = is.dev
      ? path.join(__dirname, '../../src/renderer/public/OutputSocialAds')
      : path.join(__dirname, '../renderer/OutputSocialAds')
    if (!fs.existsSync(rendererDir)) fs.mkdirSync(rendererDir, { recursive: true })
    await shell.openPath(rendererDir)
  })

  ipcMain.handle('util:downloadFile', async (_, { url, filename }) => {
    const { dialog } = require('electron')
    const { writeFile } = require('fs/promises')

    const { filePath } = await dialog.showSaveDialog({
      defaultPath: filename,
      filters: [{ name: 'Videos', extensions: ['mp4'] }]
    })

    if (!filePath) return { success: false, cancelled: true }

    try {
      const resp = await fetch(url)
      const buffer = Buffer.from(await resp.arrayBuffer())
      await writeFile(filePath, buffer)
      return { success: true, path: filePath }
    } catch (err: any) {
      return { success: false, error: err.message }
    }
  })

  // IPC Handlers: Audio
  ipcMain.handle('audio:generateSpeech', async (_, params) => {
    try {
      const result = await audioService.generateSpeech(params)
      return { success: true, data: result }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('audio:speechToSpeech', async (_, params) => {
    try {
      const result = await audioService.speechToSpeech(params)
      return { success: true, data: result }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('audio:cloneVoice', async (_, params) => {
    try {
      const result = await audioService.cloneVoice(params)
      return { success: true, data: result }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('audio:generateClonedSpeech', async (_, params) => {
    try {
      const result = await audioService.generateClonedSpeech(params)
      return { success: true, data: result }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // Save speaker embedding to disk + register in DB
  ipcMain.handle(
    'audio:saveCustomVoice',
    async (_, params: { name: string; embeddingUrl: string; samplePath?: string }) => {
      try {
        const voicesDir = path.join(app.getPath('userData'), 'custom-voices')
        if (!fs.existsSync(voicesDir)) fs.mkdirSync(voicesDir, { recursive: true })

        // Download the .safetensors embedding file from Fal CDN
        const safeName = params.name.replace(/[^a-zA-Z0-9_-]/g, '_')
        const embeddingPath = path.join(voicesDir, `${safeName}_${Date.now()}.safetensors`)
        const resp = await fetch(params.embeddingUrl)
        if (!resp.ok) throw new Error('Failed to download embedding from Fal CDN')
        const buffer = Buffer.from(await resp.arrayBuffer())
        fs.writeFileSync(embeddingPath, buffer)

        // Persist metadata to SQLite
        const id = dbService.saveCustomVoice({
          name: params.name,
          embeddingPath,
          samplePath: params.samplePath
        })

        return { success: true, data: { id, embeddingPath } }
      } catch (error: any) {
        return { success: false, error: error.message }
      }
    }
  )

  ipcMain.handle('audio:getAllCustomVoices', async () => {
    try {
      const voices = dbService.getAllCustomVoices()
      return { success: true, data: voices }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('audio:deleteCustomVoice', async (_, id: number) => {
    try {
      // Also remove the embedding file from disk
      const voices = dbService.getAllCustomVoices() as any[]
      const voice = voices.find((v) => v.id === id)
      if (voice?.embedding_path && fs.existsSync(voice.embedding_path)) {
        fs.unlinkSync(voice.embedding_path)
      }
      dbService.deleteCustomVoice(id)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('audio:playAudio', async (_, filePath) => {
    try {
      await shell.openPath(filePath)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('audio:saveAudio', async (_, filePath, destPath) => {
    const { copyFile } = require('fs/promises')
    try {
      await copyFile(filePath, destPath)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  createWindow()

  app.on('activate', function () {
    // On macOS it's common to re-create a window in the app when the
    // dock icon is clicked and there are no other windows open.
    if (BrowserWindow.getAllWindows().length === 0) createWindow()
  })
})

// Quit when all windows are closed, except on macOS. There, it's common
// for applications and their menu bar to stay active until the user quits
// explicitly with Cmd + Q.
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

