        enable_web_search: params.enable_web_search || false,
        limit_generations: params.limit_generations ?? true
      }
    } else if (params.model === 'Nano Banana 2') {
      endpoint = 'fal-ai/nano-banana-2/edit'
      body = {
        prompt: params.prompt,
        image_urls: params.image_urls,
        aspect_ratio: params.aspect_ratio || 'auto',
        num_images: params.num_images || 1,
        seed: params.seed ? parseInt(params.seed) : undefined,
        output_format: params.output_format || 'png',
        safety_tolerance: params.safety_tolerance || '4',
        limit_generations: params.limit_generations ?? true
      }
    } else if (params.model === 'Nano Banana') {
      endpoint = 'fal-ai/nano-banana/edit'
      body = {
        prompt: params.prompt,
        image_urls: params.image_urls,
        aspect_ratio: params.aspect_ratio || 'auto',
        num_images: params.num_images || 1,
        seed: params.seed ? parseInt(params.seed) : undefined,
        output_format: params.output_format || 'png',
        safety_tolerance: params.safety_tolerance || '4',
        limit_generations: params.limit_generations ?? true
      }
    } else if (params.model === 'GPT Image 2') {
      endpoint = 'openai/gpt-image-2/edit'

      // Map standard ratios to GPT Image 2 enums
      let gptImageSize = 'auto'
      const ratio = params.aspect_ratio || 'auto'
      if (ratio === '1:1') gptImageSize = 'square'
      else if (ratio === '4:3') gptImageSize = 'landscape_4_3'
      else if (ratio === '3:4') gptImageSize = 'portrait_4_3'
      else if (ratio === '16:9') gptImageSize = 'landscape_16_9'
      else if (ratio === '9:16') gptImageSize = 'portrait_16_9'
      else if (ratio === 'auto') gptImageSize = 'auto'

      body = {
        prompt: params.prompt,
        image_urls: params.image_urls,
        image_size: gptImageSize,
        quality: 'high',
        num_images: params.num_images || 1,
        output_format: params.output_format || 'png'
      }
    }

    const response = await this.request(`https://fal.run/${endpoint}`, {
      method: 'POST',
      body: JSON.stringify(body)
    })

    if (!response.ok) {
      const errText = await response.text()
      throw new Error(`Generation request failed (${response.status}): ${errText}`)
    }

    return await response.json()
  }

  /**
   * Smart Reframe — fal-ai/image-editing/reframe
   * Returns a normalized { images: [{ url }] } shape regardless of API response format.
   */
  async reframeImage(params: {
    image_url: string
    aspect_ratio: string
    output_format?: string
    guidance_scale?: number
    num_inference_steps?: number
  }): Promise<any> {
    const body = {
      image_url: params.image_url,
      aspect_ratio: params.aspect_ratio,
      output_format: params.output_format ?? 'jpeg',
      guidance_scale: params.guidance_scale ?? 3.5,
      num_inference_steps: params.num_inference_steps ?? 30
    }

    const response = await this.request('https://fal.run/fal-ai/image-editing/reframe', {
      method: 'POST',
      body: JSON.stringify(body)
    })

    if (!response.ok) {
      const errText = await response.text()
      throw new Error(`Reframe failed (${response.status}): ${errText}`)
    }

    const data = await response.json()
    console.log('[reframeImage] raw response:', JSON.stringify(data).slice(0, 400))

    // Normalize: API may return { image: {...} } OR { images: [...] }
    const url: string | undefined =
      data?.image?.url ??
      data?.images?.[0]?.url ??
      data?.output?.image?.url ??
      data?.output?.images?.[0]?.url

    if (!url)
      throw new Error(`Reframe: no image URL in response. Keys: ${Object.keys(data).join(', ')}`)
    return { images: [{ url }] }
  }

  /**
   * FLUX.1 Kontext Pro — fal-ai/flux-pro/kontext
   * Contextual image transformation with optional explicit width/height
   * for non-standard (non-enum) target dimensions.
   */
  async kontextEdit(params: {
    image_url: string
    prompt: string
    aspect_ratio?: string // standard enum formats
    width?: number // non-standard; takes precedence if provided
    height?: number // non-standard; takes precedence if provided
    output_format?: string
    num_images?: number
  }): Promise<any> {
    const body: any = {
      image_url: params.image_url,
      prompt: params.prompt,
      output_format: params.output_format ?? 'jpeg',
      num_images: params.num_images ?? 1
    }

    // Prefer explicit dimensions for non-standard ratios; fall back to enum
    if (params.width && params.height) {
      body.width = params.width
      body.height = params.height
    } else if (params.aspect_ratio) {
      body.aspect_ratio = params.aspect_ratio
    }

    const response = await this.request('https://fal.run/fal-ai/flux-pro/kontext', {
      method: 'POST',
      body: JSON.stringify(body)
    })

    if (!response.ok) {
      const errText = await response.text()
      throw new Error(`Kontext edit failed (${response.status}): ${errText}`)
    }

    const data = await response.json()
    console.log('[kontextEdit] raw response:', JSON.stringify(data).slice(0, 400))

    // Normalize: API may return { images: [...] } or { image: {...} }
    const url: string | undefined =
      data?.images?.[0]?.url ?? data?.image?.url ?? data?.output?.images?.[0]?.url

    if (!url)
      throw new Error(`Kontext: no image URL in response. Keys: ${Object.keys(data).join(', ')}`)
    return { images: [{ url }] }
  }
}

import { FalClient } from './base'

export class TextService extends FalClient {
  /**
   * ONE-SHOT VISION ANALYSIS
   * Uses the correct openrouter/router/vision schema:
   * { image_urls, prompt, system_prompt?, model, max_tokens? }
   * Returns the plain text `output` field from the response.
   */
  async analyzeImageVision(
    imageUrl: string,
    prompt: string,
    systemPrompt: string,
    modelId: string,
    maxTokens: number = 4096
  ): Promise<{ data?: string; error?: string }> {
    try {
      const apiKey = await this.getApiKey()
      const auth = `Key ${apiKey}`
      const queueUrl = 'https://queue.fal.run/openrouter/router/vision'

      const body: Record<string, any> = {
        image_urls: [imageUrl],
        prompt,
        system_prompt: systemPrompt,
        model: modelId,
        max_tokens: maxTokens
      }

      const response = await fetch(queueUrl, {
        method: 'POST',
        headers: {
          Authorization: auth,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(body)
      })

      if (!response.ok) {
        const errBody = await response.text()
        return { error: `Vision queue submit failed (${response.status}): ${errBody}` }
      }

      const queueData = await response.json()
      const result = await this.pollStatus(
        queueData.request_id,
        'openrouter/router/vision',
        120,
        auth
      )
      // The vision endpoint returns { output: string, usage: {...} }
      return { data: result?.output ?? JSON.stringify(result) }
    } catch (err: any) {
      return { error: `Network error: ${err.message}` }
    }
  }

  /**
   * MULTI-TURN CHAT COMPLETION (synchronous)
   * Uses fal.run/openrouter/router/openai/v1/chat/completions
   * This is the OpenAI-compatible bridge - it supports:
   *   - Full `messages` history array (for interview flow)
   *   - system/user/assistant roles
   *   - Plain text: wrap the prompt in a user message
   * No polling needed - response comes back directly.
   */
  async chatCompletion(
    messages: any[],
    modelId: string,
    maxTokens: number = 4096
  ): Promise<{ data?: string; error?: string }> {
    try {
      const response = await this.request(
        'https://fal.run/openrouter/router/openai/v1/chat/completions',
        {
          method: 'POST',
          body: JSON.stringify({
            model: modelId,
            messages,
            max_tokens: maxTokens
          })
        }
      )

      if (!response.ok) {
        const errBody = await response.text()
        return { error: `Chat completion failed (${response.status}): ${errBody}` }
      }

      const data = await response.json()
      // Standard OpenAI response format
      const text = data?.choices?.[0]?.message?.content ?? ''
      return { data: text }
    } catch (err: any) {
      return { error: `Network error: ${err.message}` }
    }
  }

  /**
   * Backward-compatible wrapper.
   * String prompt → wraps in a user message → calls chatCompletion.
   * Message array → calls chatCompletion directly.
   */
  async generateCopy(
    promptOrMessages: any,
    modelId: string,
    maxTokens: number = 4096
  ): Promise<{ data?: string; error?: string }> {
    const messages = Array.isArray(promptOrMessages)
      ? promptOrMessages
      : [{ role: 'user', content: promptOrMessages }]
    return this.chatCompletion(messages, modelId, maxTokens)
  }
}

import { FalClient } from './base'
import { VideoGenerationRequest, VideoGenerationResult } from './types'

export class VideoService extends FalClient {
  /**
   * Universal Video Generation Handler
   * Consolidates endpoint logic and uses model-specific payload builders.
   */
  async generateVideo(request: VideoGenerationRequest): Promise<VideoGenerationResult> {
    const apiKey = await this.getApiKey()
    const { modelId } = request
    console.log(`[VideoService:generateVideo] Targeting model: ${modelId}`)

    // 1. Configurable Endpoints
    const directRunEndpoint = `https://fal.run/${modelId}`
    const queueEndpoint = `https://queue.fal.run/${modelId}`
    const genericQueueBase = `https://queue.fal.run`

    // 2. Build Model-Specific Payload
    const payload = this.buildVideoPayload(request)
    console.log(`[VideoService:generateVideo] Payload prepared for ${modelId}`)

    const toVideoResult = (data: any): VideoGenerationResult | null => {
      const video = data?.video ?? data?.output?.video ?? data?.data?.video
      const url = video?.url ?? data?.url
      if (!url) return null

      return {
        url,
        fileName: video?.file_name ?? data?.file_name ?? 'output.mp4',
        fileSize: video?.file_size ?? data?.file_size ?? 0
      }
    }

    // --- EXECUTION: PRIMARY PATH (Direct Run) ---
    try {
      const runRes = await fetch(directRunEndpoint, {
        method: 'POST',
        headers: {
          Authorization: `Key ${apiKey}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      })

      if (runRes.ok) {
        const runData = await runRes.json()
        const parsed = toVideoResult(runData)
        if (parsed) {
          console.log(`[VideoService:generateVideo] Direct run success for ${modelId}`)
          return parsed
        }
      }
    } catch (err) {
      console.warn(
        `[VideoService:generateVideo] Direct run failed for ${modelId}, falling back to queue.`,
        err
      )
    }

    // --- EXECUTION: FALLBACK PATH (Queue + Polling) ---
    const queueSubmit = await fetch(queueEndpoint, {
      method: 'POST',
      headers: {
        Authorization: `Key ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(payload)
    })

    if (!queueSubmit.ok) {
      const errBody = await queueSubmit.text()
      throw new Error(`[${modelId}] Submit failed (${queueSubmit.status}): ${errBody}`)
    }

    const { request_id } = await queueSubmit.json()
    if (!request_id) throw new Error(`[${modelId}] No request_id returned from queue submit`)
    console.log(`[VideoService:generateVideo] Queued: ${request_id}`)

    const statusUrls = [
      `${queueEndpoint}/requests/${request_id}/status`,
      `${genericQueueBase}/requests/${request_id}/status`
    ]
    const resultUrls = [
      `${queueEndpoint}/requests/${request_id}`,
      `${genericQueueBase}/requests/${request_id}`
    ]

    // Unified Poller
    let attempts = 0
    const maxAttempts = 60 // 5 minutes at 5s intervals
    const auth = `Key ${apiKey}`

    while (attempts < maxAttempts) {
      // Check status
      for (const sUrl of statusUrls) {
        try {
          const sRes = await fetch(sUrl, { headers: { Authorization: auth } })
          if (sRes.ok) {
            const sData = await sRes.json()
            if (sData.status === 'COMPLETED') {
              // Try to get result
              for (const rUrl of resultUrls) {
                const rRes = await fetch(rUrl, { headers: { Authorization: auth } })
                if (rRes.ok) {
                  const rData = await rRes.json()
                  const parsed = toVideoResult(rData)
                  if (parsed) return parsed
                }
              }
            }
          }
        } catch (e) {
          /* ignore individual poll failure */
        }
      }

      await new Promise((r) => setTimeout(r, 5000))
      attempts++
    }

    throw new Error(`[${modelId}] Polling timed out after 5 minutes.`)
  }

  /**
   * Model-Specific Payload Mapping
   */
  private buildVideoPayload(request: VideoGenerationRequest): Record<string, unknown> {
    const { modelId } = request

    const base: Record<string, any> = {
      prompt: request.prompt,
      resolution: request.resolution,
      duration: request.duration
    }

    // Aspect Ratio mapping
    if (request.aspectRatio) {
      base.aspect_ratio = request.aspectRatio
    }

    // Negative Prompt
    if (request.negativePrompt) {
      base.negative_prompt = request.negativePrompt
    }

    // Pixverse v6 Mapping
    if (modelId.includes('pixverse')) {
      return {
        ...base,
        duration: String(request.duration), // Pixverse v6 expects string "5" or "10"
        image_url: request.imageUrl,
        generate_audio_switch: request.audio,
        thinking_type: 'disabled'
      }
    }

    // Kling Mapping (Primary)
    if (modelId.includes('kling')) {
      const klingPayload: Record<string, any> = {
        ...base,
        // Passing the numeric duration directly to allow for precision
        duration: request.duration,
        start_image_url: request.imageUrl,
        generate_audio: request.audio
      }
      if (request.endImageUrl) {
        klingPayload.end_image_url = request.endImageUrl
      }
      return klingPayload
    }

    // Default Fallback (handles most other models like Hailuo, Minimax)
    return {
      ...base,
      image_url: request.imageUrl,
      generate_audio: request.audio
    }
  }
}

import log from 'electron-log'
import { keystoreService } from '../keystore'

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// CONSTANTS
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
const GUMROAD_PRODUCT_ID = 'E68N0D3GnrI9-UgafMCUXg=='
const GUMROAD_API_URL = 'https://api.gumroad.com/v2/licenses/verify'
const REVALIDATION_DAYS = 7

export interface ActivateResult {
  success: boolean
  error?: string
  purchaserEmail?: string
}

export interface ValidateResult {
  valid: boolean
  error?: string
}

export class LicenseService {
  /**
   * Called when user enters their key for the first time.
   */
  async activate(key: string): Promise<ActivateResult> {
    try {
      const body = new URLSearchParams({
        product_id: GUMROAD_PRODUCT_ID,
        license_key: key,
        increment_uses_count: 'true'
      })

      const res = await fetch(GUMROAD_API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: body.toString()
      })
      const data = await res.json()

      // CASE 1 — data.success is false
      if (!data.success) {
        return {
          success: false,
          error: data.message
            ? `Gumroad Error: ${data.message}`
            : 'Invalid license key.\nPlease check your key and try again.'
        }
      }

      // CASE 2 — data.purchase.refunded is true
      if (data.purchase?.refunded) {
        return {
          success: false,
          error: 'This license key has been refunded\nand is no longer valid.'
        }
      }

      // CASE 3 — data.purchase.chargebacked is true
      if (data.purchase?.chargebacked) {
        return { success: false, error: 'This license key is not valid.' }
      }

      // CASE 4 — data.purchase.test is true
      if (data.purchase?.test) {
        log.info('Test key detected - allowing for test purposes')
      }

      // Determine max activations based on variant
      const variant = data.purchase?.variants || ''
      const maxActivations = variant === 'Agency' ? 5 : 2

      // CASE 5 — data.uses > maxActivations
      if (data.uses > maxActivations) {
        // Decrement uses immediately
        await fetch(GUMROAD_API_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
          body: new URLSearchParams({
            product_id: GUMROAD_PRODUCT_ID,
            license_key: key,
            increment_uses_count: 'false'
          }).toString()
        })
        return {
          success: false,
          error: `Activation limit reached (${maxActivations} devices).\nTo transfer your license, contact support.`
        }
      }

      // CASE 6 — Activation successful
      await keystoreService.setLicenseData('license-key', key)
      await keystoreService.setLicenseData('license-uses', String(data.uses))
      await keystoreService.setLicenseData('last-validated', String(Date.now()))
      await keystoreService.setLicenseData('purchaser-email', data.purchase?.email || '')

      return { success: true, purchaserEmail: data.purchase?.email }
    } catch (err: any) {
      log.error('Gumroad activation error:', err)
      return { success: false, error: 'Network error. Please check your connection.' }
    }
  }

  /**
   * Called on every app launch.
   */
  async validate(): Promise<ValidateResult> {
    try {
      // STEP 1: Read from keytar 'license-key'
      const key = await keystoreService.getLicenseData('license-key')
      if (!key) {
        return { valid: false, error: 'No license key found.' }
      }

      // STEP 2: Read 'last-validated' from keytar
      const lastValidatedStr = await keystoreService.getLicenseData('last-validated')
      const lastValidated = lastValidatedStr ? parseInt(lastValidatedStr, 10) : 0
      const daysPassed = (Date.now() - lastValidated) / (1000 * 60 * 60 * 24)

      if (daysPassed < REVALIDATION_DAYS) {
        return { valid: true }
      }

      // STEP 3: If 7 days have passed, call Gumroad
      const body = new URLSearchParams({
        product_id: GUMROAD_PRODUCT_ID,
        license_key: key,
        increment_uses_count: 'false'
      })

      const res = await fetch(GUMROAD_API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: body.toString()
      })
      const data = await res.json()

      if (!data.success) {
        await this.clearLicense()
        return { valid: false, error: 'License verification failed.' }
      }

      if (data.purchase?.refunded || data.purchase?.chargebacked) {
        await this.clearLicense()
        return { valid: false, error: 'Your license was refunded or charged back.' }
      }

      // Success
      await keystoreService.setLicenseData('last-validated', String(Date.now()))
      return { valid: true }
    } catch (err) {
      log.error('Gumroad validation error:', err)
      // If network is down, assume valid if it was previously activated
      return { valid: true }
    }
  }

  /**
   * Called when user clicks "Transfer License"
   */
  async deactivate(): Promise<void> {
    await this.clearLicense()
  }

  private async clearLicense() {
    await keystoreService.deleteLicenseData('license-key')
    await keystoreService.deleteLicenseData('license-uses')
    await keystoreService.deleteLicenseData('last-validated')
    await keystoreService.deleteLicenseData('purchaser-email')
  }
}

