interface StepChecklistProps {
  steps: Step[]
  onComplete: () => void
  estimatedTime?: string
}

export function StepChecklist({ steps, onComplete, estimatedTime }: StepChecklistProps) {
  const [currentStep, setCurrentStep] = useState(0)

  useEffect(() => {
    if (currentStep >= steps.length) {
      const timer = setTimeout(onComplete, 600) // Small pause when all are done
      return () => clearTimeout(timer)
    }

    const timer = setTimeout(() => {
      setCurrentStep((s) => s + 1)
    }, steps[currentStep].duration)

    return () => clearTimeout(timer)
  }, [currentStep, steps, onComplete])

  return (
    <div
      style={{ display: 'flex', flexDirection: 'column', gap: 14, fontFamily: 'var(--font-body)' }}
    >
      {steps.map((step, idx) => {
        const isCompleted = currentStep > idx
        const isActive = currentStep === idx
        const isPending = currentStep < idx

        return (
          <div
            key={idx}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 12,
              opacity: isPending ? 0.35 : 1,
              transition: 'opacity 0.3s'
            }}
          >
            <div
              style={{
                width: 18,
                height: 18,
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                background: isCompleted
                  ? 'rgba(34,197,94,0.15)'
                  : isActive
                    ? 'rgba(108,99,255,0.15)'
                    : 'rgba(255,255,255,0.05)',
                border: `1px solid ${isCompleted ? 'rgba(34,197,94,0.3)' : isActive ? 'var(--ma-accent)' : 'rgba(255,255,255,0.1)'}`
              }}
            >
              {isCompleted ? (
                <Check size={10} style={{ color: 'var(--ma-green)' }} />
              ) : isActive ? (
                <motion.div
                  animate={{ rotate: 360 }}
                  transition={{ repeat: Infinity, duration: 1.5, ease: 'linear' }}
                  style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                >
                  <CircleDashed size={12} style={{ color: 'var(--ma-accent)' }} />
                </motion.div>
              ) : (
                <div
                  style={{
                    width: 4,
                    height: 4,
                    borderRadius: '50%',
                    background: 'rgba(255,255,255,0.2)'
                  }}
                />
              )}
            </div>
            <span
              style={{
                fontSize: 13,
                color: isCompleted
                  ? 'rgba(255,255,255,0.8)'
                  : isActive
                    ? '#FFF'
                    : 'rgba(255,255,255,0.5)',
                textDecoration: isCompleted ? 'line-through' : 'none',
                textDecorationColor: 'rgba(255,255,255,0.2)'
              }}
            >
              {step.label}
            </span>
          </div>
        )
      })}

      {estimatedTime && (
        <div
          style={{
            marginTop: 8,
            paddingTop: 14,
            borderTop: '1px solid var(--ma-border)',
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center'
          }}
        >
          <span
            style={{
              fontSize: 11,
              color: 'rgba(255,255,255,0.3)',
              textTransform: 'uppercase',
              letterSpacing: '0.5px'
            }}
          >
            Estimated time
          </span>
          <span
            style={{
              fontSize: 11,
              color: 'var(--ma-accent-light)',
              fontFamily: 'var(--font-mono)'
            }}
          >
            {estimatedTime}
          </span>
        </div>
      )}
    </div>
  )
}

import { createContext, useContext, useState, useCallback, useEffect, ReactNode } from 'react'

export type ConnectionStatus = 'idle' | 'verifying' | 'connected' | 'invalid' | 'error' | 'required'

interface AppContextType {
  sidebarCollapsed: boolean
  setSidebarCollapsed: (v: boolean) => void
  toggleSidebar: () => void
  rightPanelContent: ReactNode
  setRightPanelContent: (content: ReactNode) => void
  onboardingComplete: boolean
  completeOnboarding: () => void
  licenseChecking: boolean
  activeImageMode: string
  setActiveImageMode: (mode: string) => void
  activeVideoMode: string
  setActiveVideoMode: (mode: string) => void
  mcpEnabled: boolean
  setMcpEnabled: (v: boolean) => void
  connectionStatus: ConnectionStatus
  falCredits: number | null
  refreshConnectionStatus: () => Promise<ConnectionStatus>
}

const AppContext = createContext<AppContextType | null>(null)

export function AppProvider({ children }: { children: ReactNode }) {
  const [sidebarCollapsed, setSidebarCollapsedState] = useState(false)
  const [rightPanelContent, setRightPanelContent] = useState<ReactNode>(null)
  const [onboardingComplete, setOnboardingComplete] = useState(() => {
    return localStorage.getItem('mosterads_onboarded') === 'true'
  })
  const [activeImageMode, setActiveImageMode] = useState('generate')
  const [activeVideoMode, setActiveVideoMode] = useState('text-to-video')
  const [mcpEnabled, setMcpEnabled] = useState(false)
  const [licenseChecking, setLicenseChecking] = useState(true)
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('idle')
  const [falCredits, setFalCredits] = useState<number | null>(null)

  const setSidebarCollapsed = useCallback((v: boolean) => {
    setSidebarCollapsedState(v)
  }, [])

  const toggleSidebar = useCallback(() => {
    setSidebarCollapsedState((prev) => !prev)
  }, [])

  const completeOnboarding = useCallback(() => {
    localStorage.setItem('mosterads_onboarded', 'true')
    setOnboardingComplete(true)
  }, [])

  const refreshConnectionStatus = useCallback(async (): Promise<ConnectionStatus> => {
    setConnectionStatus('verifying')
    try {
      // Check if any key exists first
      const existingKey = await window.api.keystore.getFalKey()
      if (!existingKey) {
        setConnectionStatus('required')
        return 'required'
      }
      // Smoke test against billing endpoint
      const result = await window.api.fal.validateKey(existingKey)
      if (result.valid) {
        setConnectionStatus('connected')
        if (result.credits !== undefined) setFalCredits(result.credits)
        return 'connected'
      } else {
        // 401 = invalid key
        setConnectionStatus('invalid')
        return 'invalid'
      }
    } catch {
      setConnectionStatus('error')
      return 'error'
    }
  }, [])

  // On mount: validate license via main process, then check fal connection
  useEffect(() => {
    const checkLicense = async () => {
      setLicenseChecking(true)
      try {
        const result = await (window as any).api.license.validate()
        if (!result.valid) {
          // License invalid — force onboarding regardless of localStorage
          setOnboardingComplete(false)
        } else if (localStorage.getItem('mosterads_onboarded') === 'true') {
          // License valid + previously onboarded — check fal connection
          refreshConnectionStatus()
        }
      } catch {
        // Network error — force onboarding so user can re-validate
        setOnboardingComplete(false)
      } finally {
        setLicenseChecking(false)
      }
    }
    checkLicense()
  }, [refreshConnectionStatus])

  return (
    <AppContext.Provider
      value={{
        sidebarCollapsed,
        setSidebarCollapsed,
        toggleSidebar,
        rightPanelContent,
        setRightPanelContent,
        onboardingComplete,
        completeOnboarding,
        licenseChecking,
        activeImageMode,
        setActiveImageMode,
        activeVideoMode,
        setActiveVideoMode,
        mcpEnabled,
        setMcpEnabled,
        connectionStatus,
        falCredits,
        refreshConnectionStatus
      }}
    >
      {children}
    </AppContext.Provider>
  )
}

export function useApp() {
  const ctx = useContext(AppContext)
  if (!ctx) throw new Error('useApp must be used within AppProvider')
  return ctx
}

