  const [copiedIndex, setCopiedIndex] = useState<number | null>(null)

  const [adLanguage, setAdLanguage] = useState('arabic')

  const compressImage = useCallback((file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader()
      reader.onload = (e) => {
        const img = new Image()
        img.onload = () => {
          const canvas = document.createElement('canvas')
          let { width, height } = img
          const maxSize = 1024
          if (width > maxSize || height > maxSize) {
            if (width > height) {
              height = (height / width) * maxSize
              width = maxSize
            } else {
              width = (width / height) * maxSize
              height = maxSize
            }
          }
          canvas.width = width
          canvas.height = height
          canvas.getContext('2d')!.drawImage(img, 0, 0, width, height)
          resolve(canvas.toDataURL('image/jpeg', 0.85))
        }
        img.src = e.target?.result as string
      }
      reader.readAsDataURL(file)
    })
  }, [])

  const handleImageUpload = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0]
      if (!file) return

      setIsGenerating(true)
      setGenerationError(null)
      setShowResults(false)

      try {
        const dataUrl = await compressImage(file)
        setProductImageUrl(dataUrl)

        const result: OneShotResult = await anthropicService.generatePlanFromImage(
          dataUrl,
          analysisModel,
          adLanguage
        )
        setAiAnalysis(result.analysis)
        setGeneratedVariants(result.variants)
        setShowResults(true)
      } catch (err: any) {
        setGenerationError(err.message)
      } finally {
        setIsGenerating(false)
      }
    },
    [analysisModel, compressImage, adLanguage]
  )

  const handleStartOver = useCallback(() => {
    setShowResults(false)
    setGeneratedVariants([])
    setGenerationError(null)
    setAiAnalysis(null)
    setProductImageUrl(null)
  }, [])

  const copyToClipboard = useCallback((text: string, idx: number) => {
    navigator.clipboard.writeText(text)
    setCopiedIndex(idx)
    setTimeout(() => setCopiedIndex(null), 2000)
  }, [])

  return {
    isGenerating,
    setIsGenerating,
    analysisModel,
    setAnalysisModel,
    adLanguage,
    setAdLanguage,
    productImageUrl,
    setProductImageUrl,
    aiAnalysis,
    setAiAnalysis,
    generatedVariants,
    setGeneratedVariants,
    generationError,
    setGenerationError,
    showResults,
    setShowResults,
    modelDropdownOpen,
    setModelDropdownOpen,
    copiedIndex,
    setCopiedIndex,
    compressImage,
    handleImageUpload,
    handleStartOver,
    copyToClipboard
  }
}

