        gap: 12
      }}
    >
      <audio ref={audioRef} src={url} hidden />

      <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
        <button
          onClick={togglePlay}
          style={{
            width: 36,
            height: 36,
            borderRadius: '50%',
            background: 'var(--ma-accent)',
            border: 'none',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: '#000',
            cursor: 'pointer',
            flexShrink: 0,
            boxShadow: '0 4px 12px var(--ma-accent-glow)'
          }}
        >
          {isPlaying ? (
            <Pause size={18} fill="currentColor" />
          ) : (
            <Play size={18} fill="currentColor" style={{ marginLeft: 2 }} />
          )}
        </button>

        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 4 }}>
          <input
            type="range"
            min="0"
            max="100"
            value={progress}
            step="0.1"
            onChange={handleSeek}
            style={{
              width: '100%',
              accentColor: 'var(--ma-accent)',
              height: 4,
              cursor: 'pointer'
            }}
          />
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span
              style={{
                fontSize: 10,
                color: 'rgba(255,255,255,0.3)',
                fontFamily: 'var(--font-mono)'
              }}
            >
              {formatTime(audioRef.current?.currentTime || 0)}
            </span>
            <span
              style={{
                fontSize: 10,
                color: 'rgba(255,255,255,0.3)',
                fontFamily: 'var(--font-mono)'
              }}
            >
              {formatTime(duration)}
            </span>
          </div>
        </div>
      </div>
    </div>
  )
}

function formatTime(seconds: number) {
  if (isNaN(seconds)) return '0:00'
  const mins = Math.floor(seconds / 60)
  const secs = Math.floor(seconds % 60)
  return `${mins}:${secs.toString().padStart(2, '0')}`
}

import { useState, useCallback } from 'react'
import { VOICE_REGISTRY, VoiceEntry } from '../../../data/voices'

export const useAudioLab = () => {
  const [script, setScript] = useState('')
  const [selectedVoice, setSelectedVoice] = useState<VoiceEntry>(VOICE_REGISTRY[0])
  const [isGenerating, setIsGenerating] = useState(false)
  const [results, setResults] = useState<any[]>([])
  const [regionFilter, setRegionFilter] = useState('')

  // Generation Settings
  const [stability, setStability] = useState(50)
  const [similarity, setSimilarity] = useState(75)
  const [speed, setSpeed] = useState(1.0)

  const handleGenerate = useCallback(async () => {
    if (!script.trim()) return
    setIsGenerating(true)
    try {
      let response: any

      // Standard ElevenLabs voice
      response = await (window as any).api.audio.generateSpeech({
        text: script,
        voiceId: selectedVoice.elevenLabsId,
        stability: stability / 100
      })

      if (response.success) {
        setResults((prev) => [
          {
            id: Date.now().toString(),
            url: response.data.url,
            text: script,
            voice: selectedVoice.name,
            createdAt: new Date().toISOString(),
            type: 'TTS'
          },
          ...prev
        ])
      } else {
        alert('Generation failed: ' + response.error)
      }
    } catch (err: any) {
      alert('Error: ' + err.message)
    } finally {
      setIsGenerating(false)
    }
  }, [script, selectedVoice, stability])

  const handlePreview = useCallback(async (voice: VoiceEntry) => {
    try {
      // 100% Free Local Preview (Method 1)
      const audioUrl = `./OutputVoices/${voice.name}.mp4`
      const audio = new Audio(audioUrl)
      audio.volume = 0.8

      await audio.play()
    } catch (err) {
      console.error('Failed to play local preview:', err)
      alert(
        `Could not play the local preview for ${voice.name}. Ensure ${voice.name}.mp4 exists in the public/OutputVoices folder.`
      )
    }
  }, [])

  return {
    script,
    setScript,
    selectedVoice,
    setSelectedVoice,
    isGenerating,
    results,
    regionFilter,
    setRegionFilter,
    stability,
    setStability,
    similarity,
    setSimilarity,
    speed,
    setSpeed,
    handleGenerate,
    handlePreview
  }
}

import { useEffect, useState, useCallback } from 'react'
import { useApp } from '../../../contexts/AppContext'

interface DashStats {
  totalGenerations: number
  mtdSpend: number
  credits: number | null
  creditsRestricted: boolean
  timeSavedH: number
  avgCostPerGen: number
}

function getMtdStart(): string {
  const d = new Date()
  d.setDate(1)
  d.setHours(0, 0, 0, 0)
  return d.toISOString()
}

export const useDashboard = () => {
  const { setRightPanelContent } = useApp()
  const [stats, setStats] = useState<DashStats | null>(null)
  const [loading, setLoading] = useState(true)
  const [refreshing, setRefreshing] = useState(false)

  const fetchData = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true)
    else setLoading(true)

    try {
      const mtdStart = getMtdStart()

      const [usageRes, billingRes] = await Promise.all([
        (window as any).api.fal.getUsage('day', mtdStart),
        (window as any).api.fal.getBilling()
      ])

      let totalGenerations = 0
      let mtdSpend = 0

      if (!('error' in usageRes)) {
        if (usageRes.summary && usageRes.summary.length > 0) {
          for (const row of usageRes.summary) {
            totalGenerations += row.quantity ?? 0
            mtdSpend += row.cost ?? 0
          }
        } else if (usageRes.time_series) {
          for (const bucket of usageRes.time_series) {
            for (const result of bucket.results) {
              totalGenerations += result.quantity ?? 0
              mtdSpend += result.cost ?? 0
            }
          }
        }
      }

      let credits: number | null = null
      let creditsRestricted = false

      if (!('error' in billingRes)) {
        if ((billingRes as any).billing_restricted) {
          creditsRestricted = true
        } else if (billingRes.credits?.current_balance !== undefined) {
          credits = billingRes.credits.current_balance
        } else if (typeof billingRes.current_balance === 'number') {
          credits = billingRes.current_balance
        } else if (typeof billingRes.credits === 'number') {
          credits = billingRes.credits
        } else if (billingRes.balance !== undefined) {
          credits = billingRes.balance
        } else {
          credits = 0
        }
      }

      setStats({
        totalGenerations: Math.round(totalGenerations),
        mtdSpend: mtdSpend,
        credits,
        creditsRestricted,
        timeSavedH: Math.round(totalGenerations * 0.15 * 10) / 10, // Round to 1 decimal
        avgCostPerGen: totalGenerations > 0 ? mtdSpend / totalGenerations : 0
      })
    } catch (err) {
      console.error('Dash fetch error:', err)
    } finally {
      setLoading(false)
      setRefreshing(false)
    }
  }, [])

  useEffect(() => {
    fetchData()
    // Auto-refresh every 2 minutes
    const timer = setInterval(() => fetchData(true), 120000)
    return () => clearInterval(timer)
  }, [])

  return {
    stats,
    loading,
    refreshing,
    refresh: () => fetchData(true),
    setRightPanelContent
  }
}

