/* ─── Ratio preview box ───────────────────────────────────────────────────── */
function RatioBox({ w, h }: { w: number; h: number }) {
  const maxW = 22
  const maxH = 28
  const ratio = w / h
  let pw: number, ph: number
  if (ratio >= 1) {
    pw = maxW
    ph = Math.max(8, Math.round(maxW / ratio))
  } else {
    ph = maxH
    pw = Math.max(8, Math.round(maxH * ratio))
  }
  return (
    <div
      style={{
        width: 24,
        height: 28,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: 0
      }}
    >
      <div
        style={{
          width: pw,
          height: ph,
          border: '1.5px solid rgba(255,255,255,0.3)',
          borderRadius: 2,
          background: 'rgba(255,255,255,0.06)'
        }}
      />
    </div>
  )
}

