/* ─── Types ───────────────────────────────────────────────────────────────── */
export type ResizeCustomDimensions = Record<string, { w: number; h: number }>

export type ResizeFormProps = {
  sourceFile: File | null
  setSourceFile: (f: File | null) => void
  selectedFormats: string[]
  setSelectedFormats: (ids: string[]) => void
  resizeModel: string
  setResizeModel: (m: string) => void
  customDimensions: ResizeCustomDimensions
  setCustomDimensions: (d: ResizeCustomDimensions) => void
  onGenerate: () => void
  generating: boolean
  totalCost: string
}

/* ─── Main Component ──────────────────────────────────────────────────────── */
export function ResizeForm({
  sourceFile,
  setSourceFile,
  selectedFormats,
  setSelectedFormats,
  resizeModel,
  setResizeModel,
  customDimensions,
  setCustomDimensions,
  onGenerate,
  generating,
  totalCost
}: ResizeFormProps) {
  const fileInputRef = useRef<HTMLInputElement>(null)

  const handleFile = useCallback(
    (file: File) => {
      if (!file.type.startsWith('image/')) return
      setSourceFile(file)
    },
    [setSourceFile]
  )

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      const file = e.dataTransfer.files[0]
      if (file) handleFile(file)
    },
    [handleFile]
  )

  const toggleFormat = useCallback(
    (id: string) => {
      const fmt = PLATFORM_FORMATS.find((f) => f.id === id)
      if (fmt && fmt.aspectRatioEnum === null && !customDimensions[id]) {
        setCustomDimensions({ ...customDimensions, [id]: { w: fmt.w, h: fmt.h } })
      }
      setSelectedFormats(
        selectedFormats.includes(id)
          ? selectedFormats.filter((x) => x !== id)
          : [...selectedFormats, id]
      )
    },
    [selectedFormats, setSelectedFormats, customDimensions, setCustomDimensions]
  )

  const setCustomW = (id: string, w: number) =>
    setCustomDimensions({ ...customDimensions, [id]: { ...(customDimensions[id] ?? {}), w } })
  const setCustomH = (id: string, h: number) =>
    setCustomDimensions({ ...customDimensions, [id]: { ...(customDimensions[id] ?? {}), h } })

  const previewUrl = sourceFile ? URL.createObjectURL(sourceFile) : null
  const modelDef = RESIZE_MODELS.find((m) => m.id === resizeModel)
  const isDisabled = generating || !sourceFile || selectedFormats.length === 0

  return (
    <div
      style={{ display: 'flex', flexDirection: 'column', gap: 10, fontFamily: 'var(--font-body)' }}
    >
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        style={{ display: 'none' }}
        onChange={(e) => {
          const f = e.target.files?.[0]
          if (f) handleFile(f)
        }}
      />

      {/* ── Row 1: Three Numbered Standalone Cards ── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 10 }}>
        {/* 1 — Source Image */}
        <div style={cardStyle}>
          <div style={cardNumRow}>
            <NumBadge n={1} />
            Source Image
          </div>
          {sourceFile && previewUrl ? (
            <div
              style={{
                position: 'relative',
                borderRadius: 8,
                overflow: 'hidden',
                minHeight: 140,
                flex: 1
              }}
            >
              <img
                src={previewUrl}
                alt="Source"
                style={{
                  width: '100%',
                  height: '100%',
                  objectFit: 'cover',
                  display: 'block',
                  minHeight: 140
                }}
              />
              <button
                onClick={(e) => {
                  e.stopPropagation()
                  setSourceFile(null)
                }}
                style={{
                  position: 'absolute',
                  top: 6,
                  right: 6,
                  width: 22,
                  height: 22,
                  borderRadius: '50%',
                  background: 'rgba(0,0,0,0.7)',
                  border: 'none',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: 'white'
                }}
              >
                <X size={11} />
              </button>
              <div
                style={{
                  position: 'absolute',
                  bottom: 0,
                  left: 0,
                  right: 0,
                  background: 'linear-gradient(transparent,rgba(0,0,0,0.65))',
                  padding: '8px 8px 6px',
                  fontSize: 9,
                  color: 'rgba(255,255,255,0.7)',
                  fontFamily: 'var(--font-mono)',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap'
                }}
              >
                {sourceFile.name}
              </div>
            </div>
          ) : (
            <div
              onDragOver={(e) => e.preventDefault()}
              onDrop={handleDrop}
              onClick={() => fileInputRef.current?.click()}
              style={{ ...dashedBox, cursor: 'pointer' }}
            >
              <Upload size={24} color="rgba(108,99,255,0.55)" />
              <span
                style={{
                  fontSize: 12,
                  fontWeight: 600,
                  color: 'rgba(255,255,255,0.65)',
                  marginTop: 4
                }}
              >
                Upload Source
              </span>
              <span
                style={{
                  fontSize: 10,
                  color: 'rgba(255,255,255,0.35)',
                  textAlign: 'center',
                  lineHeight: 1.4
                }}
              >
                Drop image or click
                <br />
                to browse
              </span>
            </div>
          )}
        </div>

        {/* 2 — Resize Engine */}
        <div style={cardStyle}>
