import type { NanoBananaThinkingLevel } from '../types'

type EstimateNanoBananaCostArgs = {
  model: string
  resolution: string
  numOutputs: number
  webSearch: boolean
  thinkingLevel: NanoBananaThinkingLevel
}

export function estimateNanoBananaCost({
  model,
  resolution,
  numOutputs,
  webSearch,
  thinkingLevel
}: EstimateNanoBananaCostArgs) {
  if (model === 'Nano Banana') {
    return (0.039 * numOutputs).toFixed(3)
  }

  if (model === 'Nano Banana 2') {
    let base = 0.08
    if (resolution === '2K') base *= 1.5
    if (resolution === '4K') base *= 2
    if (resolution === '0.5K') base *= 0.75
    if (webSearch) base += 0.015
    if (thinkingLevel === 'high') base += 0.002
    return (base * numOutputs).toFixed(3)
  }

  // Nano Banana Pro
  let base = 0.15
  if (resolution === '4K') base *= 2

  if (webSearch) base += 0.015

  return (base * numOutputs).toFixed(3)
}

import { falService } from '../../../services/fal.service'

export async function resolveImageInput(image: string | null, label: string) {
  if (!image) return null
  if (!image.startsWith('data:')) return image

  const result = await falService.uploadImageFromDataUrl(image)
  if (result.error) {
    throw new Error(`${label} upload failed: ${result.error}`)
  }

  return result.url ?? null
}

